const ctx = items[0].json;

if (!ctx.obsidian_rest_url || !ctx.obsidian_rest_api_key) {
  throw new Error('Missing OBSIDIAN_REST_URL or OBSIDIAN_REST_API_KEY');
}

const baseUrl = String(ctx.obsidian_rest_url).replace(/\/+$/, '');

function vaultUrl(path) {
  return baseUrl + '/vault/' + encodeURI(path);
}

async function obsidianGet(path) {
  return await this.helpers.httpRequest({
    method: 'GET',
    url: vaultUrl(path),
    headers: {
      Authorization: 'Bearer ' + ctx.obsidian_rest_api_key,
    },
    json: false,
    skipSslCertificateValidation: !!ctx.allow_insecure_tls,
  });
}

async function obsidianPut(path, body) {
  return await this.helpers.httpRequest({
    method: 'PUT',
    url: vaultUrl(path),
    headers: {
      Authorization: 'Bearer ' + ctx.obsidian_rest_api_key,
      'Content-Type': 'text/markdown',
    },
    body,
    json: false,
    skipSslCertificateValidation: !!ctx.allow_insecure_tls,
  });
}

async function readOrEmpty(path) {
  try {
    const content = await obsidianGet.call(this, path);
    return String(content || '');
  } catch (error) {
    const status = Number(
      (error && (error.statusCode || error.status || error.httpCode)) ||
      (error && error.response ? (error.response.status || error.response.statusCode || 0) : 0)
    );
    const isNotFound = status === 404 || /status code 404|\b404\b/i.test(String(error && error.message ? error.message : ''));
    if (isNotFound) {
      return '';
    }
    throw new Error('Obsidian read failed for "' + path + '": ' + (error.message || 'unknown error'));
  }
}

async function ensureFile(path, fallbackBody) {
  const current = await readOrEmpty.call(this, path);
  if (current.trim()) {
    return current;
  }
  const content = String(fallbackBody || '').trimEnd() + '\n';
  await obsidianPut.call(this, path, content);
  return content;
}

function tableCell(value) {
  return String(value == null ? '' : value).replace(/\|/g, '/').replace(/\n/g, ' ').trim();
}

function wiki(path, label) {
  return '[[' + String(path) + '|' + String(label) + ']]';
}

function stageTable(stageLogs) {
  const head = [
    '| step | stage | status | input_ref | output_ref | quality_score | issues | model_used | notes | ts |',
    '|---|---|---|---|---|---:|---:|---|---|---|',
  ];
  const rows = stageLogs.map((row) => {
    return [
      '| ' + tableCell(row.step),
      tableCell(row.stage),
      tableCell(row.status),
      tableCell(row.input_ref),
      tableCell(row.output_ref),
      Number(row.quality_score || 0).toFixed(2),
      tableCell(row.issues || 0),
      tableCell(row.model_used || ''),
      tableCell(row.notes || ''),
      tableCell(row.ts || '') + ' |',
    ].join(' | ');
  });
  return head.concat(rows).join('\n');
}

// 1) Write platform-specific results and drafts
await obsidianPut.call(this, ctx.output_paths.linkedin_research, ctx.generated.linkedin_research_markdown.trimEnd() + '\n');
await obsidianPut.call(this, ctx.output_paths.reddit_research, ctx.generated.reddit_research_markdown.trimEnd() + '\n');
await obsidianPut.call(this, ctx.output_paths.linkedin_draft, ctx.generated.linkedin_draft_markdown.trimEnd() + '\n');
await obsidianPut.call(this, ctx.output_paths.reddit_draft, ctx.generated.reddit_draft_markdown.trimEnd() + '\n');

// 2) Write workflow log (successful runs are always logged)
const workflowLogMarkdown = [
  '---',
  'type: workflow-log',
  'run_id: ' + ctx.run_id,
  'execution_id: ' + ctx.execution_id,
  'created_at: ' + ctx.created_at,
  'completed_at: ' + ctx.completed_at,
  'status: completed',
  'topic: "' + tableCell(ctx.topic) + '"',
  'model_used: ' + tableCell(ctx.model_used),
  '---',
  '',
  '# Workflow Log ' + ctx.run_id,
  '',
  stageTable(ctx.stage_logs || []),
  '',
  '## Ergebnisse',
  '- linkedin_ausarbeitung: ' + ctx.output_paths.linkedin_research,
  '- reddit_ausarbeitung: ' + ctx.output_paths.reddit_research,
  '- linkedin_draft: ' + ctx.output_paths.linkedin_draft,
  '- reddit_draft: ' + ctx.output_paths.reddit_draft,
  '',
  '## Modellverlauf',
  '- model_used: ' + tableCell(ctx.model_used),
].join('\n');
await obsidianPut.call(this, ctx.output_paths.workflow_log, workflowLogMarkdown.trimEnd() + '\n');

// 3) Update 00-Workflow-Ergebnisse index
const resultsHeader = [
  '# 00-Workflow-Ergebnisse',
  '',
  '| run_id | datum | thema | linkedin_ausarbeitung | reddit_ausarbeitung | linkedin_draft | reddit_draft | workflow_log |',
  '|---|---|---|---|---|---|---|---|',
].join('\n');

let resultsIndex = await ensureFile.call(this, ctx.workflow_results_index, resultsHeader);

const resultRow = [
  '| ' + tableCell(ctx.run_id),
  tableCell(ctx.completed_at.slice(0, 10)),
  tableCell(ctx.topic),
  wiki(ctx.output_paths.linkedin_research, 'LinkedIn Ausarbeitung'),
  wiki(ctx.output_paths.reddit_research, 'Reddit Ausarbeitung'),
  wiki(ctx.output_paths.linkedin_draft, 'LinkedIn Draft'),
  wiki(ctx.output_paths.reddit_draft, 'Reddit Draft'),
  wiki(ctx.output_paths.workflow_log, 'Workflow Log') + ' |',
].join(' | ');

if (!resultsIndex.includes('| ' + ctx.run_id + ' |')) {
  if (!resultsIndex.endsWith('\n')) resultsIndex += '\n';
  resultsIndex += resultRow + '\n';
  await obsidianPut.call(this, ctx.workflow_results_index, resultsIndex);
}

// 4) Update Workflow Zwischenergebnisse with Qwen summaries per step
const intermediateHeader = [
  '# Workflow Zwischenergebnisse',
  '',
  '| run_id | ts | step | stage | status | model_used | input_ref | output_ref | qwen_summary | quality_score | issues |',
  '|---|---|---|---|---|---|---|---|---|---:|---|',
].join('\n');

let intermediate = await ensureFile.call(this, ctx.workflow_intermediate_file, intermediateHeader);
const summaryByStep = {};
for (const summary of (ctx.stage_summaries || [])) {
  summaryByStep[String(summary.step)] = summary;
}

const rows = [];
for (const row of (ctx.stage_logs || [])) {
  const key = '| ' + ctx.run_id + ' | ' + row.ts + ' | ' + row.step + ' |';
  if (intermediate.includes(key)) continue;
  const summary = summaryByStep[String(row.step)] || { summary: '' };
  rows.push([
    '| ' + tableCell(ctx.run_id),
    tableCell(row.ts),
    tableCell(row.step),
    tableCell(row.stage),
    tableCell(row.status),
    tableCell(row.model_used || ctx.model_used),
    tableCell(row.input_ref),
    tableCell(row.output_ref),
    tableCell(summary.summary || ''),
    Number(row.quality_score || 0).toFixed(2),
    tableCell(row.issues || 0) + ' |',
  ].join(' | '));
}

if (rows.length) {
  if (!intermediate.endsWith('\n')) intermediate += '\n';
  intermediate += rows.join('\n') + '\n';
  await obsidianPut.call(this, ctx.workflow_intermediate_file, intermediate);
}

// 5) Ensure Workflow Schritte (detailed schema for every workflow)
const workflowSchritteContent = [
  '# Workflow Schritte',
  '',
  '## Name: WF00 System Checks',
  '### Tools: n8n, HTTP Request, SearXNG, Ollama, Obsidian REST',
  '### Schritte:',
  '1. Start Manual - startet den manuellen Checklauf.',
  '2. Check SearXNG - prueft Suchdienst erreichbar und antwortfaehig.',
  '3. Check Ollama - prueft lokale Modellverfuegbarkeit.',
  '4. Check Obsidian - prueft Obsidian REST Erreichbarkeit.',
  '### Ergebnis: Infrastrukturstatus fuer lokalen Betrieb.',
  '',
  '## Name: WF10 Research Sammeln',
  '### Tools: n8n, Code Node, SearXNG',
  '### Schritte:',
  '1. Build Queries - definiert priorisierte Rechercheanfragen.',
  '2. Search SearXNG - sammelt Suchtreffer pro Anfrage.',
  '3. Normalize Evidence - normalisiert Treffer ins Evidence-Format.',
  '### Ergebnis: Rohrecherche fuer den Hauptworkflow.',
  '',
  '## Name: WF20 Qwen Entwurf',
  '### Tools: n8n, Code Node, Ollama Qwen',
  '### Schritte:',
  '1. Build Topic Input - setzt Thema, Plattform und Tonalitaet.',
  '2. Build Qwen Prompt - erstellt den Modell-Prompt.',
  '3. Draft via Qwen - erzeugt den Entwurf.',
  '4. Collect Output - sammelt Modellantwort fuer Nachbearbeitung.',
  '### Ergebnis: Basisentwurf als JSON/Rohtext.',
  '',
  '## Name: WF30 Obsidian Schreiben',
  '### Tools: n8n, Code Node, Obsidian REST',
  '### Schritte:',
  '1. Build Note Payload - baut Markdown-Nutzlast.',
  '2. Write Note - schreibt Datei in den Obsidian-Vault.',
  '### Ergebnis: Persistierte Notiz im Vault.',
  '',
  '## Name: WF90 Workflow Orchestrator',
  '### Tools: n8n, SearXNG, Ollama Qwen, Obsidian REST',
  '### Schritte:',
  '1. Init Run Kontext - initialisiert run_id, Pfade, Modell und Laufkontext.',
  '2. Load Prompt Dateien - laedt Prompt-Dateien aus Obsidian und legt Defaults an.',
  '3. Collect Research Daten - sammelt Suchsignale mit SearXNG.',
  '4. Build Evidence Paket - verdichtet Signale in strukturierte Evidenz.',
  '5. Build Topic Brief - waehlt Thema/Angle mit Relevanzbegruendung.',
  '6. Build LinkedIn Fokus - bereitet Recherche explizit fuer LinkedIn auf.',
  '7. Build Reddit Fokus - bereitet Recherche explizit fuer Reddit auf.',
  '8. Build Draft Entwuerfe - erzeugt Entwuerfe fuer LinkedIn und Reddit.',
  '9. Run AI Kritik - entfernt KI-artige Formulierungen ohne Faktenverlust.',
  '10. Run Strategie Kritik 1 - optimiert Hook/Relevanz/CTA aus Strategieperspektive.',
  '11. Run Strategie Kritik 2 - finaler strenger Plausibilitaets- und Qualitaetscheck.',
  '12. Write Workflow Outputs - schreibt Logs, Ergebnisse, Zwischenergebnisse und Drafts.',
  '### Ergebnis: Vollstaendig geloggter Run mit verlinkten LinkedIn/Reddit-Artefakten.',
  '',
  '## Name: WF95 Fehler Logger',
  '### Tools: n8n, Error Trigger, Obsidian REST',
  '### Schritte:',
  '1. Error Trigger - reagiert auf fehlgeschlagene Workflows.',
  '2. Build Error Log - normalisiert Fehlerkontext in Logstruktur.',
  '3. Write Error Log - schreibt Fehlerlauf in Workflow Logs.',
  '### Ergebnis: Fehlgeschlagene Runs sind nachvollziehbar dokumentiert.',
].join('\n');
await obsidianPut.call(this, ctx.workflow_steps_file, workflowSchritteContent.trimEnd() + '\n');

// 6) Ensure Workflow Übersicht (all workflows + all steps)
const workflowOverviewContent = [
  '# Workflow Übersicht',
  '',
  '## Alle Workflows',
  '- WF00 System Checks',
  '- WF10 Research Sammeln',
  '- WF20 Qwen Entwurf',
  '- WF30 Obsidian Schreiben',
  '- WF90 Workflow Orchestrator',
  '- WF95 Fehler Logger',
  '',
  '## Schritte je Workflow',
  '### WF00 System Checks',
  '1. Start Manual',
  '2. Check SearXNG',
  '3. Check Ollama',
  '4. Check Obsidian',
  '',
  '### WF10 Research Sammeln',
  '1. Start Manual',
  '2. Search Web Quellen',
  '3. Build Evidence Paket',
  '4. Return Research Data',
  '',
  '### WF20 Qwen Entwurf',
  '1. Start Manual',
  '2. Generate Draft Paket',
    '',
  '### WF30 Obsidian Schreiben',
  '1. Start Manual',
  '2. Persist Workflow Output',
  '3. Return Sink Summary',
  '',
  '### WF90 Workflow Orchestrator',
  '1. Start Manual',
  '2. Init Run Kontext',
  '3. Load Prompt Dateien',
  '4. Run KI Pipeline',
  '5. Write Workflow Outputs',
  '6. Return Summary',
  '',
  '### WF95 Fehler Logger',
  '1. Catch Workflow Fehler',
  '2. Build Fehler Log',
  '3. Write Fehler Log',
  '4. Return Fehler Summary',
].join('\n');
await obsidianPut.call(this, ctx.workflow_overview_file, workflowOverviewContent.trimEnd() + '\n');

ctx.status = 'completed';
ctx.completed_at = ctx.completed_at || new Date().toISOString();

return [{ json: ctx }];
